 */
class Admin_Model_FeedbackState extends Admin_Model_Base_FeedbackState {

    const STATE_NEW = 'state-new';
    const STATE_DEFERRED = 'state-deferred';
    const STATE_SOLUTION_RUNS = 'solution-runs';
    const STATE_WAITING_APPROVE = 'state-waiting-approve';
    const STATE_NOT_APPROVED = 'state-not-approved';
    const STATE_SOLVED = 'state-solved';
    const STATE_CANCELED = 'state-canceled';
    const STATE_NOTICED = 'state-noticed';

    /**
     * @param Doctrine_Connection|null $conn
     * @throws Exception
     */
    public function save(Doctrine_Connection $conn = null) {
        $isNew = $this->ID == null;

        if ($isNew) {
            $this->DateTime = date('Y-m-d H:i:s');
            $this->User_ID = UserAdminSession::getCurrentUserID();
        }

        parent::save($conn);

        $this->feedback->updateFeedbackState($this);

        if ($isNew && $this->SendEmail) {
            \common\logic\Email\EmailFactory::sendFeedbackEmail($this->feedback, 'state', $this);
        }

    }

    /**
     * @param int $ID
     * @param string $description
     * @param string $state
     * @param bool $sendEmail
     * @throws Exception
     */
    public static function createQuickState(int $ID, string $description, string $state, string $scriptCodeContent, bool $sendEmail) : void {
        $newState = new self();

        $newState->Feedback_ID = $ID;
        $newState->State = $state;
        $newState->Description = $newState->prepareContent($description, $ID);
        $newState->ScriptCodeContent = $newState->prepareContent($scriptCodeContent, $ID);
        $newState->SendEmail = $sendEmail;

        $newState->save();
    }

    /**
     * Vrátí stavy
     * @return array
     */
    public static function getStates($forNew = false): array {
        $newStates = [
            self::STATE_NEW => translate('Nový'),

        ];

        $otherStates = [
            self::STATE_NOTICED=> translate('Beru na vědomí'),
            self::STATE_SOLUTION_RUNS => translate('V řešení'),
            self::STATE_DEFERRED => translate('Odložený'),
            self::STATE_WAITING_APPROVE => translate('Čeká na schválení'),
            self::STATE_NOT_APPROVED => translate('Neschváleno'),
            self::STATE_SOLVED => translate('Vyřešený'),
            self::STATE_CANCELED => translate('Zrušeno'),
        ];

        if ($forNew)
            return $newStates;
        else
            return array_merge($newStates, $otherStates);
    }

    /**
     * Vrátí interní stavy
     * @param bool $withoutSolved
     * @return string[]
     */
    public static function getInternalStateNames(bool $withoutSolved = false): array {
        $statesAll = [
            self::STATE_NEW,
            self::STATE_DEFERRED,
            self::STATE_SOLUTION_RUNS,
            self::STATE_WAITING_APPROVE,
            self::STATE_NOT_APPROVED,
            self::STATE_CANCELED,
            self::STATE_NOTICED,
            self::STATE_SOLVED
        ];

        $states = [
            self::STATE_NEW,
            self::STATE_DEFERRED,
            self::STATE_SOLUTION_RUNS,
            self::STATE_WAITING_APPROVE,
            self::STATE_NOT_APPROVED,
            self::STATE_NOTICED
        ];

        return $withoutSolved?$states:$statesAll;
    }

    /**
     * Vrátí stav
     * @param $state
     * @return mixed|null
     */
    public static function getState($state) {
        return self::getStates()[$state]??null;
    }

    public function getStateString() {
        return self::getState($this->State);
    }

    /**
     * @return string
     */
    private function prepareContent($description, $feedbackID) : string {
        $feedbackNumber = Admin_Model_Feedback::getFeedbackNumberByID($feedbackID);

        preg_match_all('/<img[^>]+>/i', $description, $images);
        foreach ( $images[0] as $image ) {
            preg_match_all('/src="([^"]+)"/', $image, $imageSrc);
            $fileName = 'files/feedback/' . uniqid($feedbackNumber . '_') . '.jpg';

            $imageSrc = $imageSrc[0][0];
            if (base64_to_jpeg($imageSrc, $fileName))
                $description = str_replace($imageSrc, 'src="' .  Common_Model_Eshop::getFirstEshop()->URL . '/' . $fileName . '" class="fancybox"', $description);
        }

        return html_entity_decode($description, ENT_HTML5 | ENT_NOQUOTES);
    }
}